const contact = $('Get Contact Details').first().json.contact;
const stage = $input.first().json.pipeline_stage_name;
const firstName = contact.firstName || 'Client';

const stageMessages = {
  'New Lead': 'Your case has been received and assigned to our intake team. We will contact you within 24 hours.',
  'Consultation Scheduled': 'Your consultation has been scheduled. Please check your email for appointment details.',
  'Documents Requested': 'We need a few documents to proceed with your case. Please check your email for the document checklist.',
  'Under Review': 'Your case is currently under review by our legal team. We will have an update for you within 3-5 business days.',
  'Demand Letter Sent': 'A demand letter has been sent to the opposing party. We are awaiting their response.',
  'Negotiation': 'Your case is in active negotiation. Our team is working hard to reach the best possible outcome.',
  'Settlement Reached': 'Great news! A settlement has been reached. Our team will contact you shortly to review the terms.',
  'Closed Won': 'Your case has been successfully resolved. Thank you for trusting us with your case.',
  'Closed Lost': 'After careful review, we were unable to proceed with your case. Please contact us if you have questions.'
};

const message = stageMessages[stage] || `Your case status has been updated to: ${stage}. Our team will be in touch soon.`;

return [{ json: {
  contactId: contact.id,
  firstName,
  phone: contact.phone,
  email: contact.email,
  stage,
  smsBody: `Hi ${firstName}, we have an update on your case! ${message} - Mr. Cees AI Legal Team`,
  emailSubject: `Case Update: ${stage}`,
  emailBody: `Hi ${firstName},\n\nWe wanted to keep you informed about your case progress.\n\n${message}\n\nIf you have any questions, please don't hesitate to reach out.\n\nWarm regards,\nThe Legal Team`
}}];
